import React from "react";
const experiences = [
  {
    id: 1,
    title: "Skydiving Adventure",
    description: "Experience the thrill of freefall from 15,000 feet!",
    image: "",
  },
  {
    id: 2,
    title: "Mountain Hiking",
    description: "Explore breathtaking mountains and nature trails.",

  },
  {
    id: 3,
    title: "Scuba Diving",
    description: "Dive into the ocean and discover marine life.",
    image: "https://images.unsplash.com/photo-1470770903676-69b98201ea1c?fit=crop&w=400"
  }
];

function Experience() {
  return (
    <div style={{ padding: "2px" }}>
      <h1>Our Experiences</h1>
      <div style={{ display: "flex", flexWrap: "wrap", gap: "20px" }}>
        {experiences.map(exp => (
          <div
            key={exp.id}
            style={{
              border: "1px solid #ccc",
              borderRadius: "10px",
              padding: "10px",
              width: "200px",
              textAlign: "center"
            }}
          >
            <img
              src={exp.image}
              alt={exp.title}
              style={{ width: "100%", borderRadius: "10px" }}
            />
            <h3>{exp.title}</h3>
            <p>{exp.description}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Experience;
